using HeriStep.Shared.Models.DTOs.Requests;
using HeriStep.Shared.Models.DTOs.Responses;
using BCrypt.Net;
using HeriStep.API.Data;
using HeriStep.Shared;
using HeriStep.Shared.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
namespace HeriStep.API.Controllers { [Route("api/[controller]")][ApiController] public class UsersController : ControllerBase { private readonly HeriStepDbContext _context; public UsersController(HeriStepDbContext context) => _context = context;          /*  ========================================== */ /*  1. L?Y DANH SÁCH T?NG H?P (Kèm s? s?p - Dùng cho trang Index) */ /*  ========================================== */ [HttpGet("owners-summary")] public async Task<ActionResult<IEnumerable<UserDto>>> GetOwnersSummary() { var summary = await _context.Users.Where(u => u.Role == "StallOwner").Select(u => new UserDto { Id = u.Id, Username = u.Username, FullName = u.FullName ?? "Chua d?t tên", Role = u.Role, StallCount = _context.Stalls.Count(s => (int?)s.OwnerId == u.Id) }).ToListAsync(); return Ok(summary); }          /*  ========================================== */ /*  2. L?Y DANH SÁCH CH? S?P (Dùng cho Dropdown ch?n ch? s?p) */ /*  ========================================== */ [HttpGet("owners")] public async Task<ActionResult<IEnumerable<UserDto>>> GetOwners() { return await _context.Users.Where(u => u.Role == "StallOwner").Select(u => new UserDto { Id = u.Id, Username = u.Username, FullName = u.FullName, Role = u.Role }).ToListAsync(); }          /*  ========================================== */ /*  3. T?O TÀI KHO?N M?I */ /*  ========================================== */ [HttpPost] public async Task<ActionResult> PostUser(UserDto dto) { if (await _context.Users.AnyAsync(u => u.Username == dto.Username)) return BadRequest("S? di?n tho?i này dã du?c c?p tài kho?n!");              /*  ?? T? d?ng bam m?t kh?u (M?c d?nh 123456 n?u d? tr?ng) b?ng BCrypt */ string passwordToHash = string.IsNullOrEmpty(dto.Password) ? "123456" : dto.Password; var newUser = new User { Username = dto.Username, PasswordHash = BCrypt.Net.BCrypt.HashPassword(passwordToHash), FullName = dto.FullName, Role = "StallOwner" }; _context.Users.Add(newUser); await _context.SaveChangesAsync(); return Ok(); }          /*  ========================================== */ /*  4. RESET M?T KH?U V? 123456 */ /*  ========================================== */ [HttpPut("{id}/reset-password")] public async Task<IActionResult> ResetPassword(int id) { var user = await _context.Users.FindAsync(id); if (user == null) return NotFound();              /*  ?? Bam l?i 123456 b?ng BCrypt */ user.PasswordHash = BCrypt.Net.BCrypt.HashPassword("123456"); _context.Entry(user).State = EntityState.Modified; await _context.SaveChangesAsync(); return Ok(new { message = "M?t kh?u dã du?c dua v? 123456" }); }          /*  ========================================== */ /*  5. C?P NH?T THÔNG TIN CO B?N */ /*  ========================================== */ [HttpPut("{id}")] public async Task<IActionResult> PutUser(int id, UserDto dto) { if (id != dto.Id) return BadRequest(); var existingUser = await _context.Users.FindAsync(id); if (existingUser == null) return NotFound(); existingUser.FullName = dto.FullName;              /*  ?? Ch? c?p nh?t m?t kh?u n?u Admin nh?p m?t kh?u m?i */ if (!string.IsNullOrEmpty(dto.Password)) { existingUser.PasswordHash = BCrypt.Net.BCrypt.HashPassword(dto.Password); } try { await _context.SaveChangesAsync(); } catch (DbUpdateConcurrencyException) { throw; } return NoContent(); }          /*  ========================================== */ /*  6. XÓA TÀI KHO?N */ /*  ========================================== */ [HttpDelete("{id}")] public async Task<IActionResult> DeleteUser(int id) { var user = await _context.Users.FindAsync(id); if (user == null) return NotFound(); _context.Users.Remove(user); await _context.SaveChangesAsync(); return NoContent(); } } }

